"""
MKT Christ Commentary — Luke chapter 21
Run: python3 scripts/zc-christ-luke-21-21.py

Source data used:
- data/interlinear/luke.json
- data/translation/draft/mediating/luke.json
- data/commentary/mkt-christ/luke.json (existing entries preserved)

Key decisions in this range:
- Widow's offering (vv.1-4): read typologically — her total self-giving prefigures Christ's kenosis (2 Cor 8:9)
- Temple destruction (vv.5-6): direct fulfillment of Dan 9:26; end of the sacrificial system signals Christ as the new temple (John 2:19-21)
- Olivet Discourse (vv.7-36): Luke's version is more explicit than Matt 24 on Jerusalem (v.20 names armies, not "abomination of desolation") — interpreted as distinct historical fulfillment in 70 AD + eschatological horizon
- Son of Man coming (v.27): direct citation of Dan 7:13-14
- "This generation" (v.32): treated as covering both the 70 AD generation and the final eschatological generation — Christ's words bind both horizons
- v.33 "my words will not pass away": implicit divine authority claim (only God's word exceeds creation — Ps 119:89; Isa 40:8)
- vv.37-38 summary: read as fulfillment of Isa 2:2-3 and Jer 31:34 (the teacher Israel longed for)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge new entries without overwriting any existing verse
    # CHANGE? If output path changes, update load_comm/save_comm source arg
    # VERIFY: re-run and confirm "wrote" line; spot-check ch 21 v 1 and v 27
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_21 = {
  "21": {
    "1": '<p>A revelation of God: Christ deliberately positions himself to watch the offering process, seeing what the crowds do not see — not the quantity but the proportion given. His observation establishes the divine evaluative standard by which all giving will be measured. The treasury scene is the final act of Jesus\'s temple ministry before the departure from the temple (v.37), a last act of teaching that exposes the bankruptcy of the outwardly impressive religious institution he is about to leave.</p>',
    "2": '<p>A revelation of God: the poor widow seen by Christ where she is invisible to the crowd. The theme of God\'s preferential attention to the poor runs from the Psalms (Ps 113:7-8, lifting the poor from the dust) through the Magnificat (Luke 1:52-53) and the Nazareth manifesto (4:18). The widow anticipates what Paul will say of Christ himself: "though he was rich, yet for your sake he became poor, so that you by his poverty might become rich" (2 Cor 8:9) — the same logic of total self-giving from poverty rather than surplus.</p>',
    "3": '<p>A revelation of God: Christ\'s verdict inverts the honor-shame calculus that governs the temple\'s visible economy. The rich give large amounts and receive social recognition; the widow gives almost nothing and receives Christ\'s recognition alone. The eschatological reversal that the Magnificat announced (the humble exalted, the rich sent away empty, Luke 1:52-53) is here enacted in microcosm. Christ himself is the arbiter of the true economy; his judgment is the only one that will finally stand.</p>',
    "4": '<p>A type: the widow\'s giving of "all she had to live on" (holon ton bion) is structurally parallel to Christ\'s self-offering on the cross. The rich give from surplus — from what they do not need — and their gift is comfortable for them. The widow gives everything and holds nothing back; Christ gave himself, holding nothing back (Phil 2:6-8). The type is not manufactured: Luke has already shown a pattern of reversal in which the ones who give everything (the lost son returning, the one leper giving thanks) receive the fullness of God\'s response, while those who give from surplus receive nothing new.</p>',
    "5": '<p>A theme: the disciples\' admiration for the temple\'s beauty sets up the Christological reversal — the magnificent institution that mediated access to God is about to be superseded by the one who is himself the meeting point between God and humanity. The "gifts dedicated to God" (anathemata) adorning the temple represent Israel\'s accumulated piety; Christ will shortly reveal that the entire system is coming to an end, replaced by himself (John 4:21-24, worship no longer tied to a place).</p>',
    "6": '<p>A direct prophecy: "not one stone will be left on another" is the declaration that the Mosaic temple-system is finished. Daniel 9:26 had predicted the destruction of the city and the sanctuary after the Messiah is cut off; Luke 21:6 is the Messiah himself announcing what Daniel foresaw. The physical destruction in 70 AD signals the theological reality: the sacrificial system that the temple housed has been fulfilled and terminated by Christ\'s own sacrifice (Heb 9:26; 10:1-14). Christ is the new temple — his body destroyed and raised (John 2:19-21).</p>',
    "7": '<p>A revelation of God: the disciples\' question "when will these things happen?" reflects the OT prophetic tradition of asking about the times of judgment and restoration (Dan 8:13, "How long?"; Dan 12:6, "How long shall it be?"). Christ does not rebuke the question but shapes it: the knowledge of signs is given to the community not to satisfy curiosity but to sustain faithfulness. The teacher who answers the question about the future is the same one who is the Lord of that future.</p>',
    "8": '<p>A revelation of God: Christ warns against those claiming "I am he" (ego eimi) — the very phrase that is Christ\'s own self-designation in John\'s Gospel (John 8:58, 18:5-6). The warning is only intelligible because the genuine is real: false Christs are a derivative and parasitic claim on the reality of the true Christ. Those who come claiming to be the fulfillment of eschatological hope expose by their very existence that such a fulfillment is expected — and Christ alone meets the expectation.</p>',
    "9": '<p>A revelation of God: "Do not be frightened" (mē pthoēthēte) — Christ frames the chaos of history within a sovereign providential framework. The wars and uprisings that may seem to signal the end are reinterpreted: these must happen (dei), but "the end will not come right away." The dei language (divine necessity) that governs Christ\'s own passion narrative (Luke 9:22, "the Son of Man must suffer") governs history as well. Both the cross and the wars of history are within the Father\'s plan; neither overwhelms the one who trusts the Son.</p>',
    "10": '<p>A theme: "nation against nation, kingdom against kingdom" echoes the language of divine judgment in Isaiah (Isa 19:2, Egypt against Egypt; 2 Chr 15:6). In the OT the collapse of order between nations is the signal of YHWH\'s intervention in history. Luke\'s eschatological discourse places these events within the trajectory that leads to Christ\'s return: the chaos of history is not meaningless but is the labor-pangs (Rom 8:22) of a creation groaning toward the revelation of the sons of God and the public unveiling of Christ\'s lordship.</p>',
    "11": '<p>A theme: great earthquakes, famines, and signs from heaven echo the eschatological language of Joel 2:10, 30-31 and Isa 13:10 — the prophetic template for the day of the Lord that Peter cited at Pentecost (Acts 2:19-20) as being fulfilled in Christ\'s death-resurrection-outpouring. The signs of eschatological tribulation now frame the entire age between Christ\'s first and second coming as the extended "day of the Lord" period, with its final intensification preceding the Son of Man\'s visible return.</p>',
    "12": '<p>A direct type: "before all this, they will seize you and persecute you" — the community\'s persecution is the lived extension of Christ\'s own arrest and trial. The pattern is deliberate: as Christ was handed over (paradidomi, Luke 9:44; 18:32; 22:6) so his community will be handed over (paradidomi, v.12). As he stood before kings and governors (Luke 23:1-12), so they will (v.12). The disciple is not above the teacher (Luke 6:40); the Acts narrative (Acts 4, 5, 7, 12, 21-26) records the exact fulfillment of this verse in the lives of the apostles.</p>',
    "13": '<p>A revelation of God: persecution is redesignated as evangelistic opportunity — "this will be your opportunity to bear testimony to me." The word apobasetai (will turn out, will result in) is active: God actively re-purposes the adversary\'s violence into a platform for witness. This is not merely comfort but the announcement of a Christological pattern — it was through the apparent defeat of the cross that the greatest testimony to God\'s power was given (1 Cor 1:18-25); the community\'s persecutions follow the same logic.</p>',
    "14": '<p>A revelation of God: Christ commands "make up your mind not to worry beforehand how you will defend yourselves." The prohibition on advance preparation presupposes Christ\'s intention to supply what is needed in the moment through the Spirit. This is the eschatological fulfillment of what Moses had asked for (Num 11:29, "would that all the LORD\'s people were prophets"), now given to the whole community — every disciple who stands before governors has the Spirit of the risen Christ speaking through them.</p>',
    "15": '<p>A direct revelation: "I will give you words and wisdom that none of your adversaries will be able to resist or contradict." The risen Christ through the Spirit gives his community the capacity to bear witness that surpasses their own eloquence or knowledge. Acts narrates the fulfillment precisely: Peter before the Sanhedrin (Acts 4:8-14, "they marveled"); Stephen before the council (Acts 6:10, "they could not withstand the wisdom and the Spirit with which he was speaking"). Christ\'s promise is not general but specific: the words given in the moment of trial will be adequate to the moment.</p>',
    "16": '<p>A theme: "you will be betrayed even by parents, brothers and sisters, relatives and friends" — the intimate betrayal that the disciples will experience echoes Christ\'s own betrayal by Judas, one of the Twelve. The community participates in the betrayal-pattern of the Messiah: as he was handed over by an intimate, so they will be. This is not coincidence but the extension of his suffering into theirs (Col 1:24; 2 Cor 4:10-11). The community\'s experience of betrayal is a form of participation in Christ\'s passion.</p>',
    "17": '<p>A theme: "everyone will hate you because of my name" — the name-bearing community shares the name-bearer\'s rejection. Christ himself was hated without cause (John 15:25, citing Ps 35:19/69:4), and he told the disciples explicitly that their rejection would follow his (John 15:18-19). The hatred is specific to the name: it is not the disciples themselves who are rejected but the one whose name they carry. This means their rejection is simultaneously Christ\'s rejection, and their endurance is his honor.</p>',
    "18": '<p>A revelation of God: "not a hair of your head will perish" stands in deliberate tension with v.16 ("they will put some of you to death"). The paradox is only resolved through resurrection: the martyred disciple who loses physical life in Christ\'s name is not ultimately harmed because death does not end fellowship with Christ (Phil 1:21-23; Rev 6:9-11). The promise of total preservation is eschatological rather than physical — guaranteed by the one who himself died and rose, rendering death ultimately impotent against those who are his.</p>',
    "19": '<p>A theme: "by your endurance you will gain your lives" — the endurance (hypomone) required in tribulation is itself a Christological virtue. Hebrews 12:1-3 explicitly grounds Christian endurance in Christ\'s own endurance of the cross ("looking to Jesus, the founder and perfecter of faith, who for the joy set before him endured the cross"). The life (psychas) gained through endurance is the resurrection life that mirrors Christ\'s own passage through death to life — the pattern of losing life to gain it (Luke 9:24), lived out in the community\'s tribulation.</p>',
    "20": '<p>A direct fulfillment: "when you see Jerusalem surrounded by armies, you will know that its desolation is near." Luke\'s version explicitly identifies the sign in historical terms — an encircling army — where Matthew and Mark use "the abomination of desolation" (Dan 9:27). Both point to the same event: the 70 AD siege by Titus. Daniel 9:26 predicted that after the Messiah is cut off, the city and the sanctuary will be destroyed; Luke\'s Olivet Discourse is Christ announcing the fulfillment of that Danielic prophecy as a direct consequence of Jerusalem\'s rejection of him.</p>',
    "21": '<p>A revelation of God: Christ\'s instruction to flee reflects his pastoral concern for the physical safety of his people within the coming judgment. The urgency ("let those in Judea flee to the mountains") echoes the flight from Sodom (Gen 19:17, "flee for your life") and the divine mercy that provides escape even within judgment. Eusebius records that the Jerusalem Christians did flee to Pella before the siege — the community\'s escape is thus a historical fulfillment of Christ\'s warning and an instance of divine protection within the judgment on Jerusalem.</p>',
    "22": '<p>A direct fulfillment: "this is the time of punishment in fulfillment of all that has been written." The fall of Jerusalem is not a historical accident but the comprehensive fulfillment of everything the OT warned: the covenant curses of Deuteronomy 28 (famine, siege, deportation), the Daniel 9 prediction, Hosea\'s "days of punishment" (Hos 9:7), Micah\'s prophecy of Zion\'s desolation (Mic 3:12). The "fulfillment of all that has been written" is Christological at its root: it is the rejection and crucifixion of the Messiah that triggers the judgment the OT had warned was the consequence of covenant-breaking at its ultimate level.</p>',
    "23": '<p>A revelation of God: Christ\'s compassion for the most vulnerable (pregnant women, nursing mothers) within the coming catastrophe expresses the divine character that does not delight in the destruction of the wicked (Ezek 18:23). The "great distress in the land and wrath on this people" (orgē tō laō toutō) uses the prophetic judgment-language that the OT applies to Israel\'s covenant unfaithfulness (Isa 10:3; Jer 30:7). Christ does not announce this judgment with satisfaction but with grief — consistent with his lament over Jerusalem (Luke 19:41-44).</p>',
    "24": '<p>A direct fulfillment: "they will fall by the sword and be taken as prisoners to all the nations; Jerusalem will be trampled on by the Gentiles until the times of the Gentiles are fulfilled." The sword and captivity are the precise covenant curses of Deuteronomy 28:49-64, now brought to pass. The phrase "times of the Gentiles" introduces an eschatological horizon beyond 70 AD: the period of Gentile dominance over Jerusalem is bounded ("until fulfilled"), pointing to the final coming of the Son of Man (v.27). The destruction of Jerusalem is both a completed historical fulfillment and a sign pointing toward the final consummation.</p>',
    "25": '<p>A direct prophetic fulfillment: the signs in sun, moon, and stars echo Joel 2:30-31 (which Peter cited at Pentecost as beginning fulfillment, Acts 2:19-20), Isaiah 13:10 (judgment-language for the day of the Lord), and Daniel 7:13 (the cosmic arrival of the Son of Man). Luke\'s eschatological discourse uses the prophetic imagery of cosmic disruption to frame the parousia of Christ as the ultimate divine intervention — the event toward which all OT theophanies and divine-warrior texts have been pointing. The nations\' anguish at the roaring of the sea echoes Ps 46 and Isa 17:12-13.</p>',
    "26": '<p>A theme: "people will faint from terror, apprehensive of what is coming on the world, for the heavenly bodies will be shaken." The reversal is Christological: those who feared the powers of the world (the nations, armies, persecutors) and did not fear the Son of Man will be undone when the Son of Man comes. The disciples who were told "do not be frightened" (v.9) by the same upheavals are insulated from this terror precisely because they have oriented their fear rightly — toward the one who is coming, not toward the world\'s powers (Luke 12:4-5, "fear him who has authority").</p>',
    "27": '<p>A direct citation: "they will see the Son of Man coming in a cloud with power and great glory" is the direct quotation of Daniel 7:13-14 — the climactic vision of the Ancient of Days giving dominion and glory and a kingdom to one like a son of man. Jesus applied this title to himself throughout his ministry and at his trial before the Sanhedrin explicitly combined Psalm 110:1 and Daniel 7:13 (Luke 22:69). The parousia is the public vindication of what the trial convicted as blasphemy: the condemned prisoner IS the Son of Man of Daniel 7, and all nations will finally see it.</p>',
    "28": '<p>A direct revelation: "your redemption (apolutrōsis) is drawing near." The word apolutrōsis carries both the Exodus-liberation and the slave-manumission register: it is the full, public manifestation of the liberation that Christ\'s death already accomplished (Luke 1:68, lytrōsin — Zechariah\'s Benedictus anticipated exactly this). The command to "stand up and lift your heads" is the bodily enactment of eschatological confidence: those who trust the Son of Man look toward his coming rather than cowering before the powers that surround them. The redemption is "near" because it is certain — already purchased, awaiting public display.</p>',
    "29": '<p>A theme: the fig tree had OT resonances as a symbol of Israel (Hos 9:10; Jer 24; Mic 7:1; Luke 13:6-9, the barren fig tree parable). Luke extends the comparison to "all trees" (v.29), making it universal: the signs of the kingdom\'s nearness are not restricted to Jewish historical events but are readable in the created order by all. Christ teaches from creation (the seasonal cycle) as a window onto the kingdom\'s timing — consistent with his parables throughout the Gospel, which read natural processes (seed, leaven, harvest) as disclosures of divine action.</p>',
    "30": '<p>A revelation of God: the observable sprouting of leaves that reliably signals summer is Christ\'s chosen analogy for the eschatological signs. The reliability is the point: just as no one doubts that summer follows the fig tree\'s leafing, no one should doubt that the Son of Man\'s coming follows the signs he has described. Christ\'s claim to authority over the interpretation of both creation and history is itself Christological — he speaks as the one who governs both.</p>',
    "31": '<p>A direct revelation: "you know that the kingdom of God is near." The kingdom that Christ announced at the beginning of his ministry ("the kingdom of God is at hand," Luke 4:43; 8:1) and that his miracles demonstrated as already breaking in will be fully consummated at his return. The Olivet Discourse bridges the already-inaugurated kingdom (present in Christ\'s ministry) and the not-yet-consummated kingdom (the parousia): the signs show that the final stage of its coming is imminent. Christ is both the current king and the returning king.</p>',
    "32": '<p>A revelation of God: "this generation will certainly not pass away until all these things have happened." The statement is deliberately ambiguous — covering both the generation that saw the 70 AD destruction and the final eschatological generation. The ambiguity is itself Christological: Christ\'s words bind two historical moments (70 AD and the final parousia) into a single prophetic horizon. His claim to speak with absolute certainty about both is the claim to divine foreknowledge. Whatever precise interpretation is adopted, the Christological claim is constant: Christ\'s words are as reliable as heaven and earth (v.33).</p>',
    "33": '<p>A revelation of God: "heaven and earth will pass away, but my words will never pass away." The claim exactly parallels the divine claim in Isaiah 40:8 ("the grass withers, the flower fades, but the word of our God will stand forever") and Psalm 119:89 ("forever, O LORD, your word is firmly fixed in the heavens"). No human teacher could claim this for his words; only God\'s word transcends creation. Luke\'s Jesus speaks with the permanence of the divine word — placing his own teaching in the category of Scripture (Isa 55:10-11) rather than human wisdom. This is an implicit claim to divine identity.</p>',
    "34": '<p>A theme: the warning against hearts weighed down with "carousing, drunkenness and the anxieties of life" echoes the eschatological sobriety called for throughout the NT in light of the parousia (1 Thess 5:6-8; 1 Pet 5:8; Rom 13:13-14). The particular danger is spiritual dulling rather than dramatic apostasy: the disciple who becomes absorbed in the pleasures or anxieties of ordinary life loses the orientation toward Christ\'s coming that should govern the entire period between his ascension and return. Christ\'s warning presupposes the length of the interval — long enough for hearts to drift.</p>',
    "35": '<p>A theme: "it will come on all those who live on the face of the whole earth" — the universality of the eschatological reckoning corresponds to the universality of Christ\'s lordship. The one who is Lord over all nations (Dan 7:14, "all peoples, nations, and languages shall serve him") returns as the judge of all. No person or place is exempt from the accountability of the parousia; geography cannot provide refuge from the universal judgment that the Son of Man\'s coming brings.</p>',
    "36": '<p>A direct revelation: "pray that you may be able to stand before the Son of Man." Standing before the Son of Man (Dan 7:10, the books opened, the court sitting) is the image of eschatological judgment-and-vindication. The community is summoned to pray for the capacity to stand — but not through their own righteousness; the prayer itself is the posture of dependence on Christ\'s mediation. To stand before the Son of Man as judge is possible only through union with the Son of Man as Savior. The call to watchfulness is simultaneously a call to relationship with the one before whom they will stand.</p>',
    "37": '<p>A revelation of God: the pattern of Jesus teaching in the temple by day and withdrawing to the Mount of Olives by night is the pattern of his dual identity. The temple teaching fulfills Isaiah 2:2-3 (peoples streaming to the mountain of the Lord\'s house to be taught by him) — Christ is the teacher that OT Israel longed for, embodying the instruction that the temple promised but could only shadow. The nightly withdrawal to Olivet anticipates Gethsemane (22:39): the same mountain where he teaches is where he will pray, be arrested, and begin his passion. Teaching and suffering are not separate in Luke\'s Christology.</p>',
    "38": '<p>A revelation of God: "all the people came early in the morning to hear him at the temple." The popular hunger for Christ\'s teaching is the fulfillment of the new covenant promise: "they shall all know me, from the least of them to the greatest" (Jer 31:34), and "all your children shall be taught by the LORD" (Isa 54:13). The crowds who rise early to hear Jesus are those who sense, even without full understanding, that this teacher speaks with an authority that no scribe or rabbi possesses (Luke 4:32). The scene closes the temple-teaching ministry of Jesus; after this the passion begins, and the teaching must yield to the act.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_21)
    save_comm('mkt-christ', 'luke', existing)
    ch21_count = len(existing.get('21', {}))
    print(f'Luke 21 mkt-christ: {ch21_count} verses written.')

if __name__ == '__main__':
    main()
